# Module defining shape interfaces and classes with inheritance

enum Color:
    RED = 1
    GREEN = 2
    BLUE = 3

interface Drawable:
    @abstract
    def draw(self) -> str:
        ...

interface Measurable:
    @abstract
    def get_measure(self) -> float:
        ...

class Shape(Drawable):
    color: Color

    def __init__(self, color: Color):
        self.color = color

    def describe_color(self) -> str:
        return self.color.name

    @virtual
    def dimensions(self) -> str:
        return "generic shape"

    @abstract
    def draw(self) -> str:
        ...

class Rectangle(Shape, Measurable):
    width: float
    height: float

    def __init__(self, width: float, height: float, color: Color):
        super().__init__(color)
        self.width = width
        self.height = height

    @override
    def draw(self) -> str:
        return f"Rectangle({self.width}, {self.height})"

    @override
    def get_measure(self) -> float:
        return self.width * self.height

    @override
    def dimensions(self) -> str:
        return f"{self.width}x{self.height}"

class Circle(Shape, Measurable):
    radius: float

    def __init__(self, radius: float, color: Color):
        super().__init__(color)
        self.radius = radius

    @override
    def draw(self) -> str:
        return f"Circle({self.radius})"

    @override
    def get_measure(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def dimensions(self) -> str:
        return f"r={self.radius}"

