# Module with generic utilities and structs

struct Dimension:
    width: float
    height: float

    def __init__(self, width: float, height: float):
        self.width = width
        self.height = height

    def aspect_ratio(self) -> float:
        if self.height != 0.0:
            return self.width / self.height
        return 0.0

type Transform[T] = (T) -> T

class LazyValue[T]:
    _value: T?
    _computed: bool
    _factory: () -> T

    def __init__(self, factory: () -> T):
        self._factory = factory
        self._computed = False
        self._value = None()

    def get(self) -> T:
        if not self._computed:
            self._value = Some(self._factory())
            self._computed = True
        return self._value.unwrap()

def apply_transform[T](items: list[T], transformer: Transform[T]) -> list[T]:
    result: list[T] = []
    for item in items:
        result.append(transformer(item))
    return result

def double_values(items: list[int]) -> list[int]:
    return apply_transform[int](items, lambda x: x * 2)

def compute_areas(shapes: list[Measurable]) -> list[float]:
    result: list[float] = []
    for shape in shapes:
        result.append(shape.get_measure())
    return result
